```class Solution {
public:
    string reversePrefix(string word, char ch) {
        int idx = word.find(ch);
        if (idx != string::npos) {
            string prefix = word.substr(0, idx + 1);
            reverse(prefix.begin(), prefix.end());
            return prefix + word.substr(idx + 1);
        }
        return word;
    }
};
